solution_code:
#include <iostream>

void printLine(int count, int fillChar = 45, int indent = 0, int repeat = 1)
{
    for (int r = 0; r < repeat; ++r)
    {
        for (int i = 0; i < indent; ++i)
            std::cout << ' ';
        for (int c = 0; c < count; ++c)
            std::cout << (char)fillChar;
        std::cout << '\n';
    }
}

int main()
{
    int count, fillChar, indent, repeat;
    std::cin >> count >> fillChar >> indent >> repeat;
    printLine(count, fillChar, indent, repeat);
    return 0;
}

